use std::sync::mpsc;
let (tx, rx) = mpsc::channel();
tx.send(42).unwrap();
assert_eq!(rx.recv().unwrap(), 42);

use std::sync::mpsc;
use std::thread;

let (tx, rx) = mpsc::channel();
thread::spawn(move || {
    tx.send("hello from thread").unwrap();
});
println!("{}", rx.recv().unwrap());

let (tx, rx) = mpsc::channel();
tx.send(42).unwrap();
let val = rx.recv().unwrap();

let (tx, rx) = mpsc::channel::<i32>();
match rx.try_recv() {
    Ok(val) => println!("Got: {}", val),
    Err(_) => println!("No message yet"),
}

let (tx, rx) = mpsc::channel();
tx.send(1).unwrap();
tx.send(2).unwrap();
drop(tx);
for val in rx.iter() {
    println!("{}", val);
}

let (tx, rx) = mpsc::channel();
let tx2 = tx.clone();
tx.send(1).unwrap();
tx2.send(2).unwrap();
